-- ----------------------------------------------------------------------------
-- GovernanceRoles: Table: GovernanceRoles. Part IV (Governance / Ownership) names two distinct ontology-governance roles: a Steward (responsible for the ontology's health — monitors drift, tracks external dependency updates, fields user questions, maintains docs, keeps the validation suite current; identifies that a change is needed but has no approval power) and an Authority (the power to approve changes to the CBox, ABox, and TBox; decides how and where a change is made; sits with the function that owns the domain). 'A steward who can make TBox or ABox changes without authority review is a single point of failure.' For an organization under 500 people a single person may hold both roles. This table models the maintenance discipline itself, as data, so the change log can attribute approvals to a named authority.
-- ----------------------------------------------------------------------------
INSERT INTO governance_roles (governance_role_id, display_name, kind, responsibilities, approval_scope, held_by, approved_changes)
VALUES ('gov-steward', 'Ontology Steward', 'Steward', 'Monitors the ontology for drift, tracks external-dependency updates (PROV-O, FOAF, Dublin Core, DCAT, Schema.org), fields questions from users, maintains documentation, and keeps the validation suite current. Identifies that a change is needed but does not approve it. Runs the periodic (at minimum quarterly) competency-question review: new unanswerable questions become scope-change requests, obsolete questions become deprecation candidates, and questions that return wrong answers are defects.', 'none', 'Engineering Knowledge Infrastructure team', NULL) ON CONFLICT (governance_role_id) DO NOTHING;

INSERT INTO governance_roles (governance_role_id, display_name, kind, responsibilities, approval_scope, held_by, approved_changes)
VALUES ('gov-authority', 'Ontology Authority', 'Authority', 'Holds the power to approve changes to the CBox, ABox, and TBox. Decides how and where a change is made. Reviews changes proposed by the steward so that no single person alters the knowledge graph''s semantic integrity unchecked.', 'CBox, ABox, TBox', 'Workflow Governance function', NULL) ON CONFLICT (governance_role_id) DO NOTHING;

-- ----------------------------------------------------------------------------
-- ChangeLog: Table: ChangeLog. Part IV's minimum governance artifact: 'a change log that records every TBox and ABox modification, with its rationale.' Each entry records the four facts Part IV enumerates — the competency question that motivated the change, the terms affected, the version number of the release, and the date — plus the rationale and the Authority who approved it. Semantic-versioning discipline (MAJOR.MINOR.PATCH) is captured per entry via ChangeKind.
-- ----------------------------------------------------------------------------
INSERT INTO change_log (change_log_id, version, change_date, change_kind, motivating_question, terms_affected, rationale, approved_by)
VALUES ('change-1-0-0', '1.0.0', '2026-01-15', 'major', 'All eight competency questions (CQ1-CQ8).', 'Initial release: 9 classes, 13 object properties, 5 datatype properties, 2 CBox schemes.', 'First validated release of the NTWF workflow ontology; passes the 104-test suite.', 'gov-authority') ON CONFLICT (change_log_id) DO NOTHING;

INSERT INTO change_log (change_log_id, version, change_date, change_kind, motivating_question, terms_affected, rationale, approved_by)
VALUES ('change-1-1-0', '1.1.0', '2026-03-20', 'minor', 'Which AI agent was executing this step on March 1, 2026?', 'Added filledBy assignment history (RoleAssignments) with validity periods; AIAgent deployment date; agent-type-change audit witnesses.', 'Operational governance needed retained filledBy history so historical ''as of date'' and blast-radius queries are answerable without discarding provenance. Additive and backward compatible — a minor, backward-compatible change, so per Part IV the steward is authorized to approve and deploy it without authority review.', 'gov-steward') ON CONFLICT (change_log_id) DO NOTHING;

-- ----------------------------------------------------------------------------
-- VocabularyReconciliations: Table: VocabularyReconciliations. Part IV (External dependency change): when a borrowed term from a living standard (PROV-O, FOAF, Dublin Core, DCAT, Schema.org) is deprecated and re-homed into the NTWF namespace, the edit triggers a version bump and an owl:sameAs reconciliation relation declaring the old and new terms equivalent. The worked example: deprecating foaf:name, prepending the ntwf prefix to get ntwf:name, and asserting foaf:name owl:sameAs ntwf:name. Each row is one reconciliation, with the standard it came from and the version in which the reconciliation shipped.
-- ----------------------------------------------------------------------------
INSERT INTO vocabulary_reconciliations (reconciliation_id, deprecated_term, replacement_term, reconciliation_relation, source_standard, introduced_in_version, rationale)
VALUES ('recon-foaf-name', 'foaf:name', 'ntwf:name', 'owl:sameAs', 'FOAF', 'v1.1.0', 'Part IV worked example: a deprecated FOAF element is re-prefixed into the NTWF namespace; existing data stays valid (URIs do not disappear), and foaf:name owl:sameAs ntwf:name keeps the two interchangeable for reasoners.') ON CONFLICT (reconciliation_id) DO NOTHING;

INSERT INTO vocabulary_reconciliations (reconciliation_id, deprecated_term, replacement_term, reconciliation_relation, source_standard, introduced_in_version, rationale)
VALUES ('recon-dcat-v3', 'dcat:Dataset (v2)', 'dcat:Dataset (v3)', 'owl:sameAs', 'DCAT', 'v1.1.0', 'Part IV external-dependency fact: DCAT went through a major v2 -> v3 revision that introduced new classes and deprecated others. NTWF tracks the alignment so its dcat:Dataset usage stays semantically current; existing data remains valid because URIs do not disappear.') ON CONFLICT (reconciliation_id) DO NOTHING;

